# Security utilities
class SecurityValidator:
    @staticmethod
    def validate_username(username: str) -> bool:
        if not username or len(username) < 3 or len(username) > 50:
            return False
        return bool(re.match(r'^[a-zA-Z0-9_-]+$', username))
    
    @staticmethod
    def validate_password(password: str) -> bool:
        if not password or len(password) < 8 or len(password) > 128:
            return False
        return True
    
    @staticmethod
    def validate_data_id(data_id: str) -> bool:
        if not data_id or len(data_id) > 100:
            return False
        return bool(re.match(r'^[a-zA-Z0-9_-]+$', data_id))
    
    @staticmethod
    def hash_password(password: str, salt: bytes = None) -> tuple:
        if salt is None:
            salt = secrets.token_bytes(32)
        pwd_hash = hashlib.pbkdf2_hmac('sha256', password.encode('utf-8'), salt, 100000)
        return pwd_hash, salt


class TokenManager:
    def __init__(self, secret_key: str):
        self.secret_key = secret_key
    
    def generate_token(self, username: str) -> str:
        payload = {
            'username': username,
            'exp': datetime.utcnow() + timedelta(hours=1),
            'iat': datetime.utcnow(),
            'jti': secrets.token_urlsafe(16)
        }
        return jwt.encode(payload, self.secret_key, algorithm='HS256')
    
    def validate_token(self, token: str) -> Optional[Dict]:
        try:
            payload = jwt.decode(token, self.secret_key, algorithms=['HS256'])
            return payload
        except jwt.ExpiredSignatureError:
            return None
        except jwt.InvalidTokenError:
            return None


# Secure user storage (in production, use encrypted database)
class UserStore:
    def __init__(self):
        self._users = {}
        self._init_demo_user()
    
    def _init_demo_user(self):
        pwd_hash, salt = SecurityValidator.hash_password('SecurePass123!')
        self._users['demouser'] = {
            'password_hash': pwd_hash,
            'salt': salt,
            'data': {'profile': 'Demo user profile data'}
        }
    
    def authenticate(self, username: str, password: str) -> bool:
        if username not in self._users:
            return False
        user = self._users[username]
        pwd_hash, _ = SecurityValidator.hash_password(password, user['salt'])
        return secrets.compare_digest(pwd_hash, user['password_hash'])
    
    def get_user_data(self, username: str, data_id: str) -> Optional[str]:
        if username not in self._users:
            return None
        user_data = self._users[username].get('data', {})
        return user_data.get(data_id)


# gRPC Service Implementations
class AuthServiceServicer:
    def __init__(self, user_store: UserStore, token_manager: TokenManager):
        self.user_store = user_store
        self.token_manager = token_manager
    
    def Login(self, request, context):
        # Validate input
        if not SecurityValidator.validate_username(request.username):
            context.set_code(grpc.StatusCode.INVALID_ARGUMENT)
            context.set_details('Invalid username format')
            return LoginResponse(success=False, message='Invalid username format')
        
        if not SecurityValidator.validate_password(request.password):
            context.set_code(grpc.StatusCode.INVALID_ARGUMENT)
            context.set_details('Invalid password format')
            return LoginResponse(success=False, message='Invalid password format')
        
        # Authenticate
        if self.user_store.authenticate(request.username, request.password):
            token = self.token_manager.generate_token(request.username)
            return LoginResponse(success=True, token=token, message='Login successful')
        else:
            context.set_code(grpc.StatusCode.UNAUTHENTICATED)
            context.set_details('Invalid credentials')
            return LoginResponse(success=False, message='Invalid credentials')
    
    def ValidateToken(self, request, context):
        payload = self.token_manager.validate_token(request.token)
        if payload:
            return TokenResponse(valid=True, username=payload['username'])
        else:
            context.set_code(grpc.StatusCode.UNAUTHENTICATED)
            context.set_details('Invalid or expired token')
            return TokenResponse(valid=False)


class DataServiceServicer:
    def __init__(self, user_store: UserStore, token_manager: TokenManager):
        self.user_store = user_store
        self.token_manager = token_manager
    
    def GetUserData(self, request, context):
        # Validate token
        payload = self.token_manager.validate_token(request.token)
        if not payload:
            context.set_code(grpc.StatusCode.UNAUTHENTICATED)
            context.set_details('Invalid or expired token')
            return DataResponse(success=False, message='Authentication required')
        
        username = payload['username']
        
        # Validate data_id
        if not SecurityValidator.validate_data_id(request.data_id):
            context.set_code(grpc.StatusCode.INVALID_ARGUMENT)
            context.set_details('Invalid data ID format')
            return DataResponse(success=False, message='Invalid data ID')
        
        # Retrieve data
        data = self.user_store.get_user_data(username, request.data_id)
        if data:
            return DataResponse(success=True, data=data, message='Data retrieved')
        else:
            context.set_code(grpc.StatusCode.NOT_FOUND)
            context.set_details('Data not found')
            return DataResponse(success=False, message='Data not found')


def load_tls_credentials():
    """Load TLS credentials from files"""
    with open('server.key', 'rb') as f:
        private_key = f.read()
    with open('server.crt', 'rb') as f:
        certificate_chain = f.read()
    with open('ca.crt', 'rb') as f:
        root_certificates = f.read()
    
    server_credentials = grpc.ssl_server_credentials(
        [(private_key, certificate_chain)],
        root_certificates=root_certificates,
        require_client_auth=True
    )
    return server_credentials


